head.script:
//-------------------------------------------------------------------------
// PGM명 : 월별원가실적조회 (co_404_01_12b)
// 작성자 : 송정희
// 최초작성일자 : 2026-11-14
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.sDate             = $c.date.getServerDateTime("yyyyMMdd");
	scwin.strFromDate       = scwin.sDate;			// 현재년월일을 구한다.
	scwin.strFromDate       = scwin.strFromDate.substring(0,6);

	scwin.login             = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
	scwin.privAdmin         = scwin.login.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

    scwin.wrkNo             = "";				// 작업구분코드
	scwin.fromDate          = "";			// 작업날짜

    scwin.vLoginCoCd        = $c.gus.cfIsNull(scwin.login.coCd) ? "" : scwin.login.coCd; // 소속 자회사  
    scwin.vLoginCoClsCd     = $c.gus.cfIsNull(scwin.login.coClsCd) ? "" : scwin.login.coClsCd; //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd    = scwin.login.userHomeClsCd;
    scwin.isSubCompany      = false;

    const codeOptions = [
        { grpCd : "CO012", compID : "acb_unit"}     // 단위               
    ];
    $c.data.setCommonCode(codeOptions, scwin.commonCodeCallBack);

};

scwin.commonCodeCallBack = async function () {
    ds_closeYm_search.set("sysCd", "ManagementProfitAndLossEBC");
    ds_closeYm_search.set("queryId", "retrieveManagementProfitAndLossCloseYm");
    ds_closeYm_search.set("param3", ed_coCd.getValue());
    var rs = await $c.sbm.execute(sbm_closeYm);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_closeYm.setJSON(rs.responseJSON.GAUCE);
	    // co_ds_combo1.sort("code", 0);
    };
    ica_FromDate.setValue(ds_closeYm.getCellData(0, "col1"));

    ds_hidden.set("hid_FromDate", ica_FromDate.getValue());

    acb_version.hide("");

    scwin.f_LoadVer();

    $c.gus.cfDisableKey();

    acb_unit.setSelectedIndex(1);

    acb_srchBookClsCd.setSelectedIndex(0);

	scwin.f_setCompanyInfo();

    // $p.setTimeout(function() {
    //     // ica_FromDate.setValue("202501");
    //     // ed_sacctDeptCd.setValue("01087");
    //     // ed_sacctDeptCd.focus();
    //     // ed_sacctDeptCd.blur();
    //     chk_lowerDeptIncluYn.setValue(1);
    //     ica_FromDate.setValue("202512");
    //     ed_sacctDeptCd.setValue("00047");
    //     ed_sacctDeptCd.focus();
    //     ed_sacctDeptCd.blur();
    // }, {"delay":50});

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (orgObjCd, orgObjNm, select_code, flag) {
    var rtnList = new Array();

    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    switch (select_code) {
        // 조회조건용 수금부서 PopUp 호출(물류 귀속부서만 POPUP에 포함)

        case '1' :
            var pWhere = ds_searchMonthCostResult.get("closeYm")+",,,,,,,,,"+ed_coCd.getValue();
            udc_sacctDeptCd.setSelectId('retrieveAcctDeptCdInfo');
            udc_sacctDeptCd.cfCommonPopUp(function(rtnList){
                if (rtnList != null) {
                    if (rtnList[0] == "N/A") return;
                    ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
                } else {
                    ds_searchMonthCostResult.set("acctDeptLvl", 0);
                }
                scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);

            },cd, nm,"T",null,null,null,null,pWhere,"450","500",null,null); // 귀속부서
            break;
        // 조회조건용 사업영역
        case '2' :
            udc_sbizDom.setSelectId('retrieveBizDomCdInfo');
            udc_sbizDom.cfCommonPopUp(function(rtnList){
                if (rtnList != null) {
                    if (rtnList[0] == "N/A") return;
                    ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
                } else {
                    ds_searchMonthCostResult.set("acctDeptLvl", 0);
                }
                scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);

            },cd, nm,"T",null,null,null,null,"1,,,,,","450","500",null,null); // 사업영역
            break;
        default :
            await $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
};

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList){
    if (rtnList != null ) {
        if (rtnList[0] == "N/A" ) return ;
        orgObjCd.setValue(rtnList[0]);	// 코드값
        orgObjNm.setValue(rtnList[1]);	// 코드명
        orgObjCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
        orgObjNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
        ds_searchMonthCostResult.set("acctDeptLvl", rtnList[6]);
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.options.hidVal = "";
        orgObjNm.options.hidVal = "";
        ds_searchMonthCostResult.set("acctDeptLvl", 0);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    ds_searchMonthCostResult.set("distYn", "1");	// 배부포함여부를 항상 포함으로 고정함.(2006.04.13)
    if (ed_sacctDeptCd.getValue().trim() != "" ) {
        // 조회조건 필수사항 체크
        if (!await $c.gus.cfValidate([ica_FromDate,ed_sacctDeptCd,acb_version, ed_coCd])) {
            return;
        }
    } else if (ed_sbizDomCd.getValue().trim() != "" ) {
        // 조회조건 필수사항 체크
        if (!await $c.gus.cfValidate([ica_FromDate,ed_sbizDomCd,acb_version, ed_coCd])) {
            return;
        }
    } else {
        await $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }

    // 귀속부서로 조회 할 경우
    if (ed_sacctDeptCd.getValue().trim() != "" ) {
        ds_searchMonthCostResult.set("acctDeptCd", acb_acctDeptCd.getValue());
        ds_searchMonthCostResult.set("bizDomCd", "");
    // 사업영역으로 조회 할 경우
    } else if (ed_sbizDomCd.getValue().trim() != "" ) {
        if (ed_coCd.getValue() == "000") {
            ds_searchMonthCostResult.set("acctDeptCd", "00000");
        } 
        ds_searchMonthCostResult.set("bizDomCd", acb_acctDeptCd.getValue());
    } else {
        await $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }
    $c.sbm.execute(sbm_searchMonthCostResult);

};

//-------------------------------------------------------------------------
// Ver정보를 가져온다.
//-------------------------------------------------------------------------
scwin.f_LoadVer = async function () {
    // 작업구분코드 및 날짜 세팅함수 호출
    scwin.fromDate = ica_FromDate.getValue().trim();

    ds_version_search.set("sysCd", "ManagementProfitAndLossEBC");
    ds_version_search.set("queryId", "retrieveMonthEachProgressResultsVer");
    ds_version_search.set("param1", scwin.fromDate);
    var rs = await $c.sbm.execute(sbm_version);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_version.setJSON(rs.responseJSON.GAUCE);
	    // co_ds_combo1.sort("code", 0);
    };

    /* (2006.04.18) 계획의 버전이 아닌 실적의 버전을 DISTINCT해서 가져오도록 함.
            ds_version.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
                                                    "&queryId=retrieveVersionInfo" +
                                                    "&param1=" + scwin.fromDate;
    */

    await scwin.f_SetFinalVer();

    /* (2006.05.29) 버전 002(경평)으로만 조회토록 setting */		
    acb_version.setSelectedIndex(0);
    acb_version.setValue("002");

};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = async function () {
    if (ds_version.getRowCount() < 1) return;
    var index = 0;
    for (i = 0 ; i < ds_version.getRowCount() ; i++) {
        if (ds_version.getCellData(i, "ds_version.Reset();") == 1) {
            index = i-1;
            break;
        }
    }
    acb_version.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = async function () {
    if (ed_coCd.getValue() != "000") {
        if (ed_sacctDeptCd.getValue().trim() == "" ) {
            await $c.gus.cfAlertMsg("부서는 필수 입력 입니다.");
            return;
        }
    }
    ds_dept_search.set("sysCd", "");
    ds_dept_search.set("queryId", "");
    ds_dept_search.set("param1", "");
    ds_dept_search.set("param2", "");
    ds_dept_search.set("param3", "");
    ds_dept_search.set("param4", "");
    ds_dept_search.set("param5", "");
    ds_dept_search.set("param7", "");

    // 사업여역이 NULL일경우 귀속부서는 필수 입력임
    if (ed_sacctDeptCd.getValue().trim() != "") {
        // 조회조건 필수사항 체크
        if (!await $c.gus.cfValidate([ica_FromDate,ed_sacctDeptCd,acb_version])) {
            return;
        }
        ds_dept_search.set("sysCd", "ManagementProfitAndLossEBC");
        ds_dept_search.set("queryId", "retrievePlanComparisonResultsAcctDept");

        ds_dept_search.set("param1", ed_sacctDeptCd.getValue().trim());
        ds_dept_search.set("param2", ica_FromDate.getValue().trim());
        ds_dept_search.set("param3", ds_searchMonthCostResult.get("lowerDeptIncluYn"));
        ds_dept_search.set("param4", ds_searchMonthCostResult.get("acctDeptLvl"));
        ds_dept_search.set("param5", ds_searchMonthCostResult.get("ver"));
        ds_dept_search.set("param7", ed_coCd.getValue());

    // 귀속부서가 NULL일경우 사업영역은 필수임
    } else if (ed_sbizDomCd.getValue().trim() != "" ) {
        // 조회조건 필수사항 체크
        if (!await $c.gus.cfValidate([ica_FromDate,ed_sbizDomCd,acb_version])) {
            return;
        }
        ds_dept_search.set("sysCd", "BusinessDomainEBC");
        ds_dept_search.set("queryId", "retrievePlanComparisonResultsBizDomCd");

        ds_dept_search.set("param1", ed_sbizDomCd.getValue().trim());
        ds_dept_search.set("param3", ds_searchMonthCostResult.get("lowerDeptIncluYn"));
        ds_dept_search.set("param7", ed_coCd.getValue());

    } else {
        await $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }

    var rs = await $c.sbm.execute(sbm_dept);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        // ds_dept event=OnLoadCompleted(rowCnt)>
        ds_dept.setJSON(rs.responseJSON.GAUCE);
        ds_dept.sort("col1", 0);
        scwin.f_Retrieve();
    };
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
