//-------------------------------------------------------------------------
// 해당월의 실적이 있는지 여부 확인(True:테이타가 있음, False:데이타가 없음)
// 해당월의 실적이 없을경우 누적으로 해서 보여주므로 당월 마이너스 실적 나오는것을 막기위함 함수.
//-------------------------------------------------------------------------
scwin.f_getRowCount = async function () {
    var ebcId = "ManagementProfitAndLossEBC";
    var queryId = "retrieveManagementProfitAndLossCountBizDom";
    var param1 = acb_version.getValue();	// 버전
    var param2 = ica_FromDate.getValue().trim();	// 결산년월
    var param3 = ed_coCd.getValue().trim();			// 회사코드

    ds_tempCount_search.set("sysCd", ebcId);
    ds_tempCount_search.set("queryId", queryId);
    ds_tempCount_search.set("param1", param1);
    ds_tempCount_search.set("param2", param2);
    ds_tempCount_search.set("param3", param3);

    var rs = await $c.sbm.execute(sbm_tempCount);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_tempCount.setJSON(rs.responseJSON.GAUCE);
    };

    // 해당년월 버전의 데이타가 있음
    //if (parseInt(ds_tempCount.NameValue(1,"col1")) > 0 ) {
    //	return true;
    //}
    // 해당년월 버전의 데이타가 없음
    return true;
    // ds_searchMonthCostResult.set("eisAcctDeptCd") = "1";
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = async function () {
    // 해당월의 실적이 있는지 여부 확인(True:테이타가 있음, False:데이타가 없음)
    if (!await scwin.f_getRowCount() ) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;	
    }

    if (ds_dept.getRowCount() == 0){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;	
    }

    gen_gridView1.removeAll();

    scwin.f_Export2();

    // for ( var i = ds_dept.getRowCount() ; i >= 0 ; i-- ){
    //     ds_searchMonthCostResult.set("acctDeptCd", ds_dept.getCellData(i, "col1"));
    //     $c.sbm.execute(sbm_searchMonthCostResult);
    //     scwin.f_Export2(ds_dept.NameString(i,"COL2"))
    // }		
};

//---------------------------------------------------------------------------------------
// 엑셀 Download  <하위부서 Excel Down Load : 하위부서포함한 전체 를 excel 파일로 저장 >--2007.04.17
//---------------------------------------------------------------------------------------
scwin.f_Export2 = async function (){
    var dataList = ds_multipleExcel;
    var dataListNm = "ds_multipleExcel_";
    var h_row1 = ["1월", "2월", "3월", "4월", "5월", "6월", "상반기계", "7월", "8월", "9월", "10월", "11월", "12월", "하반기계"];
    // 생성할 데이터리스트 컬럼 세팅 
    var colInfoJSON = [];
    for (var i = 0; i < dataList.getTotalCol(); i++) {
        var colInfo = {
              "id": dataList.getColumnID(i)
            , "dataType": "text"
            , "name": dataList.getColumnName(i)
        };
        colInfoJSON.push(colInfo);
    };

    // 파일명 : ex) 월별원가실적조회_시화센터운송_202501_ver_200_하위
    var fileName = "월별원가실적조회_" + acb_acctDeptCd.getText(true) + "_" + ica_FromDate.getValue() + "_ver_" + acb_version.getValue() + "_하위";
    // 최종 넘길 json
    var options = {
        common: {
            fileName: fileName+".xlsx",     // [default: excel.xls] 다운로드하려는 파일의 이름
            showProcess : true,             // [default: true] 다운로드 시 프로세스 창을 보여줄지 여부
            multipleSheet : "true",         // [default: true] 다운로드시 dataList별 sheet분리 출력유무
        },
        // 시트별 정보
        excelInfo: []
    };
    for (var i = 0 ; i < ds_dept.getRowCount() ; i++) {
        // 동적 생성할 데이터리스트에 담을 데이터 조회
        ds_searchMonthCostResult.set("acctDeptCd", ds_dept.getCellData(i, "col1"));
        var rs = await $c.sbm.execute(sbm_searchMonthCostResultForExcel);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            var rowCnt = ds_monthCostResult.getRowCount();
            if (rowCnt == 0 ){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
            }
        }
        if (ds_monthCostResult.getRowCount() == 0) {
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
			continue;
		}

        // 동적 생성할 데이터 리스트 정보
        var dsName = dataListNm;
        var dataListId = dsName + i;
        var dltObj = $c.util.getComponent(dataListId);
        if (!$c.util.isEmpty(dltObj)) {
