//-------------------------------------------------------------------------
// 그리드 포맷설정
//-------------------------------------------------------------------------
scwin.f_SetGridFormat = function (pageNum) {
    scwin.pageNum = pageNum;
    if ($c.gus.cfIsNull(pageNum)) pageNum = 1;

    let halfYy1 = ["jan", "janPercent", "feb", "febPercent", "mar", "marPercent", "apr", "aprPercent", "may", "mayPercent", "jun", "junPercent", "halfYy", "halfYyPercent"];
    let halfYy2 = ["jul", "julPercent", "aug", "augPercent", "sep", "sepPercent", "oct", "octPercent", "nov", "novPercent", "dec", "decPercent", "halfYy2", "halfYy2Percent"];

    let showCols, hideCols;

    if (pageNum == 1) {
        showCols = halfYy1;
        hideCols = halfYy2;
        btn_pageNum1.setDisabled(true);
        btn_pageNum2.setDisabled(false);        
    } else {
        hideCols = halfYy1;
        showCols = halfYy2;
        btn_pageNum1.setDisabled(false);
        btn_pageNum2.setDisabled(true);    
    }

    showCols.forEach(colId => {
        gr_monthCostResult.setColumnVisible(colId, true);
    });
    hideCols.forEach(colId => {
        gr_monthCostResult.setColumnVisible(colId, false);
    });
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function () {
    scwin.cunit = 1;
    if (acb_unit.getValue() == "02") { 
        scwin.cunit = 1000;      
    }
    if (acb_unit.getValue() == "03") { 
        scwin.cunit = 1000000;   
    }
    if (acb_unit.getValue() == "04") { 
        scwin.cunit = 100000000; 
    }
    scwin.f_changeUnitAmt(scwin.cunit);   
}

