    //             ds_monthCostResult.setCellData(scwin.i, cols[scwin.j], "0");
    //         } else { 
    //             var setVal = $c.num.round($c.num.parseFloat(ds_monthCostResult.getCellData(scwin.i, cols[scwin.j]))/unitAmt,0);
    //             if (setVal == 0) {
