};

scwin.unitFormatt = function (dataVal) {
    if ($c.gus.cfIsNull(dataVal) || !$c.num.isNumber(dataVal)) {
        return 0; 
    } else {
        var setVal = dataVal / scwin.cunit;
        if (dataVal == 0) {
            return 0; 
        } else {
            if (Math.round(setVal, 0) == 0 && dataVal < 0){
                return 0; 
            } else {
                return $c.num.formatNumber(Math.round(setVal, 0),0);
            }
        }
    }
};

//-------------------------------------------------------------------------
// 각월에 대한 %비율을 계산한다. (원금액 / 매출총금액 *100)
//-------------------------------------------------------------------------
scwin.f_CalPercent = function (dataList) {
    var dataList_rcnt = dataList.getRowCount();
    if (dataList.getRowCount() == 0) {
        return;
    }
    const cols = ["amt", "jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec", "halfYy", "halfYy2"];    
    for (var i = 0 ; i < dataList_rcnt ; i ++) {
        for (var j = 0 ; j < cols.length ; j ++){
            var colValue  = dataList.getCellData(i, cols[j]);
            var colValue0 = dataList.getCellData(0, cols[j]);

            if (colValue0 == 0) {
                // dataList.setCellData(i, cols[j] + "Percent", "-1.#");
                dataList.setCellData(i, cols[j] + "Percent", 0);

            } else {
                colValue = colValue / colValue0 * 100;
                colValue = colValue * 100;
                colValue = Math.round(colValue) / 100;

                var intValArr = colValue.toString().split('.');
                if (intValArr.length > 1) {
                    colValue = $c.num.parseFloat(intValArr[0] + "." + intValArr[1].slice(0, 1));
                } else {
                    colValue = intValArr[0];
                }

                dataList.setCellData(i, cols[j] + "Percent", colValue);
            }

        }
    }

};

//자회사 회계 시스템 추가에 따른 설정 
scwin.f_setCompanyInfo = function () {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    // scwin.f_PopUpCompanyInfo('T'); 

    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(function(rtnList){
        // SET
        if (rtnList != null ) {
            if (rtnList[0] == "N/A") return;
            ed_coCd.setValue(rtnList[0]);  	// 코드
            ed_coNm.setValue(rtnList[5]); 	// 회사명 
            ds_hidden.set("txtCoClsCd", rtnList[1]);	// 회사구분 
        }else{
            ed_coCd.setValue("");
            ed_coNm.setValue("");
            ds_hidden.set("txtCoClsCd", "");
        }

        if (ds_hidden.get("txtCoClsCd") > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            // $c.gus.cfEnableObjects([ed_coCd,ed_coNm,img_company ]);
            $c.gus.cfEnableObjects([udc_coCd]);
        }else {
            // $c.gus.cfDisableObjects([ed_coCd,ed_coNm,img_company  ]);
            $c.gus.cfDisableObjects([udc_coCd]);
        }
    }
    ,ed_coCd.getValue(), ed_coNm.getValue()
    ,"T",null,null,null,null
    ,null,null,null,null,null
    );


};

